TaskConfig = {}
TaskConfig.TaskList = {}
TaskConfig.TaskGroupList = {}
TaskConfig.TaskGroupWeight = {}

function TaskConfig:init(task_list)
    for _, task in pairs(task_list) do
        local item = {
            Id = tonumber(task.id),
            Desc = task.desc or "",
            GroupId = tonumber(task.groupId),
            NextTaskId = tonumber(task.nextTaskId),
            TaskTypeId = tonumber(task.type),
            RefreshCycle = tonumber(task.refreshCycle),
            GoalNum = tonumber(task.num),
            Remarks = StringUtil.split(task.remarks, "#"),
            GameTypes = StringUtil.split(task.gameType, "#"),
            Reward = tonumber(task.reward),
            Weight = tonumber(task.weight),
            RewardIds = StringUtil.split(task.RewardIds or "", "#"),
        }
        self.TaskList[item.Id] = item
        self.TaskGroupList[tostring(item.GroupId)] = self.TaskGroupList[tostring(item.GroupId)] or {}
        table.insert(self.TaskGroupList[tostring(item.GroupId)], item)

        if item.GroupId ~= nil then
            if not self.TaskGroupWeight[item.GroupId] then
                self.TaskGroupWeight[item.GroupId] = item.Weight
            else
                self.TaskGroupWeight[item.GroupId] = self.TaskGroupWeight[item.GroupId] + item.Weight
            end
        end
    end
end

function TaskConfig:getTaskById(taskId)
    return self.TaskList[taskId]
end

function TaskConfig:getTaskByGroupId(groupId)
    return self.TaskGroupList[tostring(groupId)]
end

function TaskConfig:getWeight(groupId)
    return self.TaskGroupWeight[groupId]
end

function TaskConfig:getRandomTask(groupId)
    local tasks = self:getTaskByGroupId(groupId)
    local random = math.random(1, tasks.taskWeightSum)
    local weightSum = 0
    for _, task in pairs(tasks) do
        weightSum = weightSum + task.Weight
        if weightSum >= random then
            return task
        end
    end
end

TaskConfig:init(FileUtil.getConfigFromCsv("setting/TaskSetting.csv"))